const VerificationStatusBadge: React.FC<{ result?: VerificationResult, onClick?: () => void, isReverifying?: boolean }> = ({ result, onClick, isReverifying }) => {
    if (isReverifying) return <div className="p-1"><Spinner className="w-3.5 h-3.5" /></div>;
    if (!result) return null;

    const config = {
        'green': { icon: VerifiedShield, text: 'Verified', bg: 'bg-emerald-50 dark:bg-emerald-950/30 text-emerald-700 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/30', tooltip: 'Matched in RxNorm with valid strength.' },
        'yellow': { icon: ReviewEye, text: 'Review', bg: 'bg-amber-50 dark:bg-amber-950/30 text-amber-700 dark:text-amber-400 border-amber-100 dark:border-amber-900/30', tooltip: 'Partial match. Human spelling verification recommended.' },
        'red': { icon: AlertShield, text: 'Invalid', bg: 'bg-rose-50 dark:bg-rose-950/30 text-rose-700 dark:text-rose-400 border-rose-100 dark:border-rose-900/30', tooltip: 'Strength mismatch detected for this ingredient.' },
        'gray': { icon: ReviewEye, text: 'Pending', bg: 'bg-gray-100 text-gray-800 border-gray-200', tooltip: 'Awaiting clinical verification.' }
    };

    const style = config[result.color] || config['gray'];
    const Icon = style.icon;
    const isInteractive = result.color !== 'green' && onClick;

    return (
        <div className="group relative">
            <motion.button 
                whileTap={isInteractive ? { scale: 0.95 } : {}}
                onClick={isInteractive ? onClick : undefined}
                className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-wide border ${style.bg} ${isInteractive ? 'cursor-pointer hover:brightness-95' : 'cursor-default'}`} 
            >
                <Icon className="w-3.5 h-3.5" />
                {style.text}
            </motion.button>

            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-3 py-1.5 bg-zinc-900 text-white text-[9px] font-bold rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap shadow-2xl z-50">
                {style.tooltip}
                <div className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-zinc-900" />
            </div>
        </div>
    );
};

const EditableField: React.FC<{ 
    label: string; 
    value: string; 
    onChange: (v: string) => void; 
    multiline?: boolean; 
    disabled?: boolean; 
    rightElement?: React.ReactNode;
    onFocus?: () => void;
    onBlur?: () => void;
    maskType?: 'date' | 'dosage';
    placeholder?: string;
}> = ({ label, value, onChange, multiline, disabled, rightElement, onFocus, onBlur, maskType, placeholder }) => {
    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        onChange(e.target.value);
    };

    return (
        <div className="mb-3">
            <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1.5 flex justify-between items-center h-5">
                {label} 
                {rightElement}
            </label>
            {multiline ? 
                <textarea 
                    value={value} 
                    onChange={handleInputChange} 
                    disabled={disabled} 
                    placeholder={placeholder}
                    rows={3} 
                    onFocus={onFocus}
                    onBlur={onBlur}
                    className="w-full bg-white/60 dark:bg-black/40 backdrop-blur-sm border border-slate-200 dark:border-slate-700 rounded-xl p-3 text-sm text-slate-900 dark:text-white focus:ring-2 focus:ring-brand-blue outline-none disabled:opacity-50 transition-all hover:bg-white/80 dark:hover:bg-white/5 resize-none" 
                /> : 
                <input 
                    type="text" 
                    value={value} 
                    onChange={handleInputChange} 
                    disabled={disabled} 
                    placeholder={placeholder}
                    onFocus={onFocus}
                    onBlur={onBlur}
                    className="w-full bg-white/60 dark:bg-black/40 backdrop-blur-sm border border-slate-200 dark:border-slate-700 rounded-xl p-3 text-sm text-slate-900 dark:text-white focus:ring-2 focus:ring-brand-blue outline-none disabled:opacity-50 transition-all hover:bg-white/80 dark:hover:bg-white/5" 
                />
            }
        </div>
    );
};

