                /> : 
                <input 
                    type="text" 
                    value={value} 
                    onChange={handleInputChange} 
                    disabled={disabled} 
                    placeholder={placeholder}
                    onFocus={onFocus}
                    onBlur={onBlur}
                    className="w-full bg-white/60 dark:bg-black/40 backdrop-blur-sm border border-slate-200 dark:border-slate-700 rounded-xl p-2.5 text-[13px] font-medium text-slate-900 dark:text-white focus:ring-2 focus:ring-brand-blue/20 outline-none disabled:opacity-50 transition-all hover:bg-white/80 dark:hover:bg-white/5" 
