    if (!result) return null;

    // Fix: Updated config keys to match VerificationColor type and fixed comparison on line 118.
    const config: Record<string, { icon: any, text: string, bg: string, tooltip: string }> = {
        'emerald': { icon: VerifiedShield, text: 'Verified', bg: 'bg-emerald-50 dark:bg-emerald-950/30 text-emerald-700 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/30', tooltip: 'Matched in RxNorm with valid strength.' },
