import { useState, useEffect, useRef } from 'react';
import { supabase } from '../lib/supabaseClient.ts';
import { Session } from '@supabase/supabase-js';

export type User = { name: string; email: string; id: string };

export const useAuthSession = () => {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);
  const timeoutRef = useRef<any>(null);

  useEffect(() => {
    // Safety Timeout: If Supabase doesn't respond in 2.5s, proceed as guest
    timeoutRef.current = setTimeout(() => {
      if (loading) {
        console.warn("Auth check timed out. Proceeding in offline/guest mode.");
        setLoading(false);
      }
    }, 2500);

    // 1. Check active session
    supabase.auth.getSession().then(({ data: { session }, error }) => {
      if (error) console.error("Supabase Auth Error:", error);

      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
      }

      clearTimeout(timeoutRef.current);
      setLoading(false);
    }).catch(() => {
      clearTimeout(timeoutRef.current);
      setLoading(false);
    });

    // 2. Listen for changes
    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      if (session?.user) {
        setUser({
          name: session.user.user_metadata?.full_name || session.user.email?.split('@')[0] || 'User',
          email: session.user.email || '',
          id: session.user.id
        });
        setIsLoggedIn(true);
      } else {
        setUser(null);
        setIsLoggedIn(false);
      }
      setLoading(false);
    });

    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      subscription.unsubscribe();
    };
  }, []);

  const login = (userData: any) => { /* Managed by onAuthStateChange */ };

  const logout = async () => {
    await supabase.auth.signOut();
  };

  return { user, isLoggedIn, login, logout, loading };
};

import { useState, useEffect, useRef } from 'react';
import { PrescriptionData } from '../types.ts';
import { useAuthSession } from './useAuthSession.ts';
import * as dbService from '../services/databaseService.ts';
import { syncLocalToCloud } from '../services/syncService.ts';

export const useMedicalHistory = () => {
  const [history, setHistory] = useState<PrescriptionData[]>([]);
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);
  const { isLoggedIn, user, loading: authLoading } = useAuthSession();
  const hasSyncedRef = useRef(false);

  useEffect(() => {
    // Don't start loading history until we know the auth state
    if (authLoading) return;

    let mounted = true;

    const loadData = async () => {
      setIsLoadingHistory(true);
      try {
        // 1. If Just Logged In -> Attempt Sync
        if (isLoggedIn && !hasSyncedRef.current) {
            try {
              await syncLocalToCloud();
              hasSyncedRef.current = true;
            } catch (syncError) {
              console.warn("Background sync failed, proceeding with local load.");
            }
        }

        // 2. Load History (Routes to Supabase or IDB automatically)
        const dbData = await dbService.getAllPrescriptions();

        if (mounted) {
            setHistory(dbData || []);
        }
      } catch (e) {
        console.error("Critical: Failed to load medical history:", e);
      } finally {
        if (mounted) {
            setIsLoadingHistory(false);
        }
      }
    };

    loadData();

    return () => { mounted = false; };
  }, [isLoggedIn, user, authLoading]);

  const saveToHistory = async (dataToSave: PrescriptionData) => {
    const dataWithTimestamp = {
        ...dataToSave,
        timestamp: dataToSave.timestamp || new Date().toISOString()
    };

    setHistory(prevHistory => {
        const existingIndex = prevHistory.findIndex(h => h.id === dataWithTimestamp.id);
        if (existingIndex > -1) {
            const newHistory = [...prevHistory];
            newHistory[existingIndex] = dataWithTimestamp;
            return newHistory;
        } else {
            return [dataWithTimestamp, ...prevHistory];
        }
    });

    try {
        await dbService.savePrescription(dataWithTimestamp);
        const freshData = await dbService.getAllPrescriptions();
        setHistory(freshData || []);
    } catch (e) {
        console.error("Failed to persist to DB:", e);
    }
  };

  const deleteFromHistory = async (idToDelete: string) => {
    if (!idToDelete) return;
    setHistory(prevHistory => prevHistory.filter(h => h.id !== idToDelete));
    try {
        await dbService.deletePrescription(idToDelete);
    } catch (e) {
        console.error("Failed to delete from DB:", e);
        const freshData = await dbService.getAllPrescriptions();
        setHistory(freshData || []);
    }
  };

  return { history, saveToHistory, deleteFromHistory, isLoadingHistory };
};

